namespace UniversityCatalog.Models;

public class Department
{
    public int Id { get; set; }
    public string Code { get; set; } = string.Empty;
    public string Name { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}

public class Instructor
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Email { get; set; } = string.Empty;
    public string Bio { get; set; } = string.Empty;
    public string PhotoUrl { get; set; } = string.Empty;
}

public class CourseSchedule
{
    public string Days { get; set; } = string.Empty;
    public string Time { get; set; } = string.Empty;
    public string Location { get; set; } = string.Empty;
    public string Semester { get; set; } = string.Empty;
}

public class Course
{
    public int Id { get; set; }
    public string Code { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Credits { get; set; }
    public int DepartmentId { get; set; }
    public string DepartmentName { get; set; } = string.Empty;
    public bool IsFeatured { get; set; }
    public Instructor Instructor { get; set; } = new();
    public CourseSchedule Schedule { get; set; } = new();
}

public class EnrollmentRequest
{
    public string StudentName { get; set; } = string.Empty;
    public string StudentId { get; set; } = string.Empty;
    public int CourseId { get; set; }
}

using UniversityCatalog.Models;

namespace UniversityCatalog.Services;

public interface ICatalogService
{
    List<Department> GetDepartments();
    List<Course> GetAllCourses();
    List<Course> GetFeaturedCourses();
    List<Course> SearchCourses(string? searchTerm, int? departmentId);
    Course? GetCourseById(int id);
    List<Course> GetCoursesByDepartment(int departmentId);
    bool SubmitEnrollment(EnrollmentRequest request);
}

public class CatalogService : ICatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Instructor> _instructors;
    private readonly List<Course> _courses;

    public CatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Code = "CS", Name = "Computer Science", Description = "Study of computation, algorithms, and information systems." },
            new() { Id = 2, Code = "MATH", Name = "Mathematics", Description = "Pure and applied mathematics, statistics, and data analysis." },
            new() { Id = 3, Code = "PHYS", Name = "Physics", Description = "Study of matter, energy, and the fundamental forces of nature." },
            new() { Id = 4, Code = "ENG", Name = "English", Description = "Literature, composition, creative writing, and linguistics." },
            new() { Id = 5, Code = "HIST", Name = "History", Description = "World history, cultural studies, and historical analysis." },
        };

        _instructors = new List<Instructor>
        {
            new() { Id = 1, Name = "Dr. Ada Lovelace", Title = "Professor", Email = "alovelace@university.edu", Bio = "Dr. Lovelace specializes in algorithms and computational theory. She has published over 50 papers and received the Distinguished Teaching Award three years running.", PhotoUrl = "" },
            new() { Id = 2, Name = "Dr. Alan Turing", Title = "Associate Professor", Email = "aturing@university.edu", Bio = "Dr. Turing's research focuses on artificial intelligence and machine learning. He leads the university's AI Research Lab and mentors graduate students.", PhotoUrl = "" },
            new() { Id = 3, Name = "Dr. Emmy Noether", Title = "Professor", Email = "enoether@university.edu", Bio = "Dr. Noether is a leading researcher in abstract algebra and theoretical physics. Her work on symmetry and conservation laws is internationally recognized.", PhotoUrl = "" },
            new() { Id = 4, Name = "Dr. Richard Feynman", Title = "Professor", Email = "rfeynman@university.edu", Bio = "Dr. Feynman is renowned for making complex physics concepts accessible. His lecture series has become a cornerstone of the department's curriculum.", PhotoUrl = "" },
            new() { Id = 5, Name = "Dr. Maya Angelou", Title = "Professor", Email = "mangelou@university.edu", Bio = "Dr. Angelou brings decades of creative writing experience. She has authored six novels and mentors the university's literary magazine.", PhotoUrl = "" },
            new() { Id = 6, Name = "Dr. Howard Zinn", Title = "Associate Professor", Email = "hzinn@university.edu", Bio = "Dr. Zinn specializes in social movements and American history. His courses emphasize primary source analysis and critical thinking.", PhotoUrl = "" },
        };

        _courses = new List<Course>
        {
            new() { Id = 1, Code = "CS 101", Title = "Introduction to Computer Science", Description = "An introductory course covering fundamental concepts of programming, data structures, and algorithmic thinking. Students will learn Python and build small projects.", Credits = 3, DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = true, Instructor = _instructors[0], Schedule = new() { Days = "Mon, Wed, Fri", Time = "9:00 AM – 9:50 AM", Location = "Science Hall 201", Semester = "Fall 2026" } },
            new() { Id = 2, Code = "CS 301", Title = "Data Structures & Algorithms", Description = "In-depth study of arrays, linked lists, trees, graphs, sorting, and searching algorithms. Includes analysis of time and space complexity.", Credits = 4, DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = true, Instructor = _instructors[0], Schedule = new() { Days = "Tue, Thu", Time = "10:30 AM – 11:45 AM", Location = "Science Hall 305", Semester = "Fall 2026" } },
            new() { Id = 3, Code = "CS 450", Title = "Artificial Intelligence", Description = "Survey of AI techniques including search, knowledge representation, machine learning, neural networks, and natural language processing.", Credits = 3, DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = false, Instructor = _instructors[1], Schedule = new() { Days = "Mon, Wed", Time = "2:00 PM – 3:15 PM", Location = "Tech Building 110", Semester = "Fall 2026" } },
            new() { Id = 4, Code = "MATH 201", Title = "Calculus II", Description = "Continuation of Calculus I covering techniques of integration, series, parametric equations, and polar coordinates.", Credits = 4, DepartmentId = 2, DepartmentName = "Mathematics", IsFeatured = false, Instructor = _instructors[2], Schedule = new() { Days = "Mon, Wed, Fri", Time = "11:00 AM – 11:50 AM", Location = "Math Building 102", Semester = "Fall 2026" } },
            new() { Id = 5, Code = "MATH 310", Title = "Linear Algebra", Description = "Vector spaces, linear transformations, matrices, determinants, eigenvalues, and applications to systems of equations.", Credits = 3, DepartmentId = 2, DepartmentName = "Mathematics", IsFeatured = true, Instructor = _instructors[2], Schedule = new() { Days = "Tue, Thu", Time = "1:00 PM – 2:15 PM", Location = "Math Building 205", Semester = "Fall 2026" } },
            new() { Id = 6, Code = "PHYS 101", Title = "General Physics I", Description = "Mechanics, thermodynamics, and waves. Includes weekly lab sessions with hands-on experiments.", Credits = 4, DepartmentId = 3, DepartmentName = "Physics", IsFeatured = false, Instructor = _instructors[3], Schedule = new() { Days = "Mon, Wed, Fri", Time = "10:00 AM – 10:50 AM", Location = "Physics Lab 100", Semester = "Fall 2026" } },
            new() { Id = 7, Code = "PHYS 301", Title = "Quantum Mechanics", Description = "Introduction to quantum theory: wave functions, Schrödinger equation, angular momentum, and hydrogen atom.", Credits = 3, DepartmentId = 3, DepartmentName = "Physics", IsFeatured = true, Instructor = _instructors[3], Schedule = new() { Days = "Tue, Thu", Time = "3:00 PM – 4:15 PM", Location = "Physics Lab 302", Semester = "Fall 2026" } },
            new() { Id = 8, Code = "ENG 201", Title = "Creative Writing", Description = "Workshop-based course in fiction and poetry writing. Students develop original works and participate in peer review sessions.", Credits = 3, DepartmentId = 4, DepartmentName = "English", IsFeatured = false, Instructor = _instructors[4], Schedule = new() { Days = "Tue, Thu", Time = "9:00 AM – 10:15 AM", Location = "Humanities 401", Semester = "Fall 2026" } },
            new() { Id = 9, Code = "ENG 350", Title = "American Literature", Description = "Survey of major American literary works from the colonial period through the 21st century with emphasis on cultural context.", Credits = 3, DepartmentId = 4, DepartmentName = "English", IsFeatured = false, Instructor = _instructors[4], Schedule = new() { Days = "Mon, Wed", Time = "1:00 PM – 2:15 PM", Location = "Humanities 210", Semester = "Fall 2026" } },
            new() { Id = 10, Code = "HIST 101", Title = "World History to 1500", Description = "A global survey of civilizations, cultures, and events from prehistory through the late medieval period.", Credits = 3, DepartmentId = 5, DepartmentName = "History", IsFeatured = false, Instructor = _instructors[5], Schedule = new() { Days = "Mon, Wed, Fri", Time = "1:00 PM – 1:50 PM", Location = "Liberal Arts 120", Semester = "Fall 2026" } },
            new() { Id = 11, Code = "CS 220", Title = "Web Development", Description = "Full-stack web development covering HTML, CSS, JavaScript, and server-side frameworks. Students build and deploy a complete web application.", Credits = 3, DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = false, Instructor = _instructors[1], Schedule = new() { Days = "Mon, Wed", Time = "4:00 PM – 5:15 PM", Location = "Tech Building 215", Semester = "Fall 2026" } },
            new() { Id = 12, Code = "MATH 410", Title = "Probability & Statistics", Description = "Probability theory, random variables, distributions, hypothesis testing, regression, and applications to data science.", Credits = 3, DepartmentId = 2, DepartmentName = "Mathematics", IsFeatured = false, Instructor = _instructors[2], Schedule = new() { Days = "Mon, Wed, Fri", Time = "2:00 PM – 2:50 PM", Location = "Math Building 310", Semester = "Fall 2026" } },
        };
    }

    public List<Department> GetDepartments() => _departments;

    public List<Course> GetAllCourses() => _courses;

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public List<Course> SearchCourses(string? searchTerm, int? departmentId)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue && departmentId.Value > 0)
        {
            query = query.Where(c => c.DepartmentId == departmentId.Value);
        }

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Code.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Instructor.Name.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public Course? GetCourseById(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> GetCoursesByDepartment(int departmentId) =>
        _courses.Where(c => c.DepartmentId == departmentId).ToList();

    public bool SubmitEnrollment(EnrollmentRequest request)
    {
        // In production this would persist to a database
        return !string.IsNullOrWhiteSpace(request.StudentName)
            && !string.IsNullOrWhiteSpace(request.StudentId)
            && request.CourseId > 0
            && _courses.Any(c => c.Id == request.CourseId);
    }
}

