{"file_text": "@* Displays a single featured course as a card on the homepage *@

<div class="card h-100 shadow-sm border-primary">
    <div class="card-body">
        <span class="badge bg-primary mb-2">@Course.Code</span>
        <h5 class="card-title">@Course.Title</h5>
        <p class="card-text text-muted">@Course.DepartmentName &middot; @Course.Credits credits</p>
        <p class="card-text">@Truncate(Course.Description, 100)</p>
    </div>
    <div class="card-footer bg-transparent">
        <a href="@($"course/{Course.Id}")" class="btn btn-outline-primary btn-sm">View Details</a>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
