arguments.file_text:
@page "/"
@using UniversityCatalog.Services
@using UniversityCatalog.Components.Shared
@inject ICatalogService CatalogService

<PageTitle>University Course Catalog</PageTitle>

<div class="text-center mb-5">
    <h1 class="display-5 fw-bold">University Course Catalog</h1>
    <p class="lead text-muted">Explore departments, discover courses, and enroll for the upcoming semester.</p>
    <a href="catalog" class="btn btn-primary btn-lg me-2">Browse All Courses</a>
    <a href="enroll" class="btn btn-outline-secondary btn-lg">Enroll Now</a>
</div>

<h2 class="mb-3">Featured Courses</h2>
<div class="row row-cols-1 row-cols-md-2 row-cols-lg-4 g-4 mb-5">
    @foreach (var course in _featured)
    {
        <div class="col">
            <FeaturedCourseCard Course="course" />
        </div>
    }
</div>

<h2 class="mb-3">Departments</h2>
<div class="row row-cols-2 row-cols-md-3 row-cols-lg-5 g-3">
    @foreach (var dept in _departments)
    {
        <div class="col">
            <DepartmentLinkCard Department="dept" />
        </div>
    }
</div>

@code {
    private List<Models.Course> _featured = new();
    private List<Models.Department> _departments = new();

    protected override void OnInitialized()
    {
        _featured = CatalogService.GetFeaturedCourses();
        _departments = CatalogService.GetDepartments();
    }
}

@page "/catalog"
@rendermode InteractiveServer
@using UniversityCatalog.Services
@using UniversityCatalog.Components.Shared
@inject ICatalogService CatalogService

<PageTitle>Course Catalog</PageTitle>

<h1 class="mb-4">Course Catalog</h1>

<CatalogFilters Departments="_departments"
                SearchTerm="@_searchTerm"
                SearchTermChanged="OnSearchChanged"
                SelectedDepartmentId="@_departmentId"
                SelectedDepartmentIdChanged="OnDepartmentChanged" />

@if (_filteredCourses.Count == 0)
{
    <div class="alert alert-info">No courses match your search criteria.</div>
}
else
{
    <p class="text-muted mb-3">Showing @_filteredCourses.Count course(s)</p>
    @foreach (var course in _filteredCourses)
    {
        <CourseCard Course="course" />
    }
}

@code {
    private List<Models.Department> _departments = new();
    private List<Models.Course> _filteredCourses = new();
    private string _searchTerm = string.Empty;
    private int _departmentId;

    [SupplyParameterFromQuery(Name = "departmentId")]
    public int? QueryDepartmentId { get; set; }

    protected override void OnInitialized()
    {
        _departments = CatalogService.GetDepartments();
        if (QueryDepartmentId.HasValue)
        {
            _departmentId = QueryDepartmentId.Value;
        }
        ApplyFilters();
    }

    private void OnSearchChanged(string term)
    {
        _searchTerm = term;
        ApplyFilters();
    }

    private void OnDepartmentChanged(int deptId)
    {
        _departmentId = deptId;
        ApplyFilters();
    }

    private void ApplyFilters()
    {
        _filteredCourses = CatalogService.SearchCourses(
            string.IsNullOrWhiteSpace(_searchTerm) ? null : _searchTerm,
            _departmentId > 0 ? _departmentId : null);
    }
}

@page "/course/{CourseId:int}"
@using UniversityCatalog.Services
@using UniversityCatalog.Components.Shared
@inject ICatalogService CatalogService

<PageTitle>@(_course?.Title ?? "Course Not Found")</PageTitle>

@if (_course is null)
{
    <div class="alert alert-warning">Course not found.</div>
    <a href="catalog" class="btn btn-outline-primary">Back to Catalog</a>
}
else
{
    <nav aria-label="breadcrumb" class="mb-3">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="catalog">Catalog</a></li>
            <li class="breadcrumb-item active" aria-current="page">@_course.Code</li>
        </ol>
    </nav>

    <div class="d-flex justify-content-between align-items-start mb-3">
        <div>
            <h1>@_course.Title</h1>
            <span class="badge bg-secondary me-2">@_course.Code</span>
            <span class="badge bg-primary">@_course.Credits credits</span>
            <span class="ms-2 text-muted">@_course.DepartmentName</span>
        </div>
        <a href="@($"enroll?courseId={_course.Id}")" class="btn btn-success">Enroll</a>
    </div>

    <div class="mb-4">
        <h5>Description</h5>
        <p>@_course.Description</p>
    </div>

    <div class="row">
        <div class="col-md-6">
            <CourseScheduleCard Schedule="_course.Schedule" />
        </div>
        <div class="col-md-6">
            <InstructorBioCard Instructor="_course.Instructor" />
        </div>
    </div>

    <a href="catalog" class="btn btn-outline-secondary mt-2">← Back to Catalog</a>
}

@code {
    [Parameter]
    public int CourseId { get; set; }

    private Models.Course? _course;

    protected override void OnInitialized()
    {
        _course = CatalogService.GetCourseById(CourseId);
    }
}

@page "/enroll"
@using UniversityCatalog.Services
@inject ICatalogService CatalogService

<PageTitle>Enrollment Request</PageTitle>

<h1 class="mb-4">Enrollment Request</h1>

@if (_submitted)
{
    <div class="alert alert-success">
        <h4 class="alert-heading">Request Submitted!</h4>
        <p>Thank you, <strong>@_model.StudentName</strong>. Your enrollment request for
            <strong>@(_courses.FirstOrDefault(c => c.Id == _model.CourseId)?.Title ?? "the selected course")</strong>
            has been received. You will receive a confirmation email at your university account.</p>
        <hr />
        <a href="catalog" class="btn btn-outline-success">Browse More Courses</a>
        <a href="enroll" class="btn btn-success ms-2">Submit Another</a>
    </div>
}
else
{
    @if (_error is not null)
    {
        <div class="alert alert-danger">@_error</div>
    }

    <div class="row">
        <div class="col-md-8 col-lg-6">
            <form method="post" @formname="enrollment" @onsubmit="HandleSubmit">
                <AntiforgeryToken />

                <div class="mb-3">
                    <label for="studentName" class="form-label">Full Name</label>
                    <input type="text" class="form-control" id="studentName" name="Model.StudentName"
                           value="@_model.StudentName" required />
                </div>

                <div class="mb-3">
                    <label for="studentId" class="form-label">Student ID</label>
                    <input type="text" class="form-control" id="studentId" name="Model.StudentId"
                           value="@_model.StudentId" required placeholder="e.g. S-12345" />
                </div>

                <div class="mb-3">
                    <label for="courseId" class="form-label">Course</label>
                    <select class="form-select" id="courseId" name="Model.CourseId" required>
                        <option value="">— Select a course —</option>
                        @foreach (var course in _courses)
                        {
                            if (course.Id == _model.CourseId)
                            {
                                <option value="@course.Id" selected>@course.Code – @course.Title</option>
                            }
                            else
                            {
                                <option value="@course.Id">@course.Code – @course.Title</option>
                            }
                        }
                    </select>
                </div>

                <button type="submit" class="btn btn-primary">Submit Enrollment Request</button>
                <a href="catalog" class="btn btn-outline-secondary ms-2">Cancel</a>
            </form>
        </div>
    </div>
}

@code {
    [SupplyParameterFromForm(FormName = "enrollment")]
    private Models.EnrollmentRequest _model { get; set; } = new();

    [SupplyParameterFromQuery(Name = "courseId")]
    public int? QueryCourseId { get; set; }

    private List<Models.Course> _courses = new();
    private bool _submitted;
    private string? _error;

    protected override void OnInitialized()
    {
        _courses = CatalogService.GetAllCourses();
        if (QueryCourseId.HasValue && _model.CourseId == 0)
        {
            _model.CourseId = QueryCourseId.Value;
        }
    }

    private void HandleSubmit()
    {
        if (string.IsNullOrWhiteSpace(_model.StudentName) ||
            string.IsNullOrWhiteSpace(_model.StudentId) ||
            _model.CourseId <= 0)
        {
            _error = "Please fill in all fields.";
            return;
        }

        var success = CatalogService.SubmitEnrollment(_model);
        if (success)
        {
            _submitted = true;
            _error = null;
        }
        else
        {
            _error = "Unable to process your request. Please verify your information and try again.";
        }
    }
}

